def is_prime(n):
    if n < 2:
        return False
    for i in range(2, int(n**0.5) + 1):
        if n % i == 0:
            return False
    return True

# Examples:
# is_prime(7)  → True
# is_prime(10) → False

def factorial(n):
    if n <= 1:
        return 1
    return n * factorial(n - 1)

# Iterative version:
def factorial_iter(n):
    result = 1
    for i in range(2, n + 1):
        result *= i
    return result

class Stack:
    def __init__(self):
        self._items = []

    def push(self, item):
        self._items.append(item)

    def pop(self):
        if self.is_empty():
            raise IndexError('pop from empty stack')
        return self._items.pop()

    def peek(self):
        if self.is_empty():
            raise IndexError('peek at empty stack')
        return self._items[-1]

    def is_empty(self):
        return len(self._items) == 0

    def size(self):
        return len(self._items)

Binary search finds an element in a sorted array by repeatedly dividing the search range in half.

def binary_search(arr, target):
    left, right = 0, len(arr) - 1
    while left <= right:
        mid = (left + right) // 2
        if arr[mid] == target:
            return mid
        elif arr[mid] < target:
            left = mid + 1
        else:
            right = mid - 1
    return -1  # Not found

# Time: O(log n), Space: O(1)
# For 1 million elements: max 20 comparisons

